INSERT INTO status_messages (content, type) VALUES ('Tip: Use /stats to see your progress across 28 error types.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /gemini, /qwen, /deepseek, or /ollama to switch LLM providers.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Stuck? Use /help to see all available commands.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: igt --handbook generates a personalized grammar guide based on your mistakes.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Try /practice to generate exercises for your most frequent errors.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /vocab <word> to look up a word and save it to your personal vault.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "The quick brown fox jumps over the lazy dog" is a pangram, using every letter in the alphabet.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Queueing" is the only word in English with five consecutive vowels.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The most commonly used word in English is "the".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Set" has more definitions than any other word in the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "alphabet" comes from the first two letters of the Greek alphabet: alpha and beta.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Underground" is the only word in the English language that begins and ends with the letters "und."', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Article Usage) The word "the" is a definite article; "a" and "an" are indefinite articles.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The Oxford Comma is the final comma in a list of three or more items.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Spelling) "I before E except after C" is a common rule, but it has many exceptions like "weird".', 'grammar_fact');
INSERT INTO status_messages (content, type, author) VALUES ('"To have another language is to possess a second soul."', 'quote', 'Charlemagne');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the blood of the soul into which thoughts run and out of which they grow."', 'quote', 'Oliver Wendell Holmes');
INSERT INTO status_messages (content, type, author) VALUES ('"One language sets you in a corridor for life. Two languages open every door along the way."', 'quote', 'Frank Smith');
INSERT INTO status_messages (content, type, author) VALUES ('"Knowledge of languages is the doorway to wisdom."', 'quote', 'Roger Bacon');
INSERT INTO status_messages (content, type, author) VALUES ('"Change your language and you change your thoughts."', 'quote', 'Karl Albrecht');
INSERT INTO status_messages (content, type, author) VALUES ('"Learning is a treasure that will follow its owner everywhere."', 'quote', 'Chinese Proverb');
